CREATE TABLE IF NOT EXISTS articles (id SERIAL PRIMARY KEY, title VARCHAR(500) NOT NULL, slug VARCHAR(500) NOT NULL UNIQUE, excerpt TEXT, content TEXT, image_url TEXT, seo_title VARCHAR(500), seo_description TEXT, is_published BOOLEAN DEFAULT false, sort_order INT DEFAULT 0, published_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS site_content (id SERIAL PRIMARY KEY, key VARCHAR(255) NOT NULL UNIQUE, value TEXT, description VARCHAR(500), updated_at TIMESTAMPTZ DEFAULT NOW());